insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('activationfunction', 'Activation function', '', '', ARRAY['activation function','activation']::text[], 'Core', 'The little on/off-ish dial inside a neuron that lets a network bend, not just draw straight lines.', 'A dimmer switch, not a light switch — it decides how much of a signal passes through, and “a little” is what makes curves possible.', 'Swap every ReLU in a network for nothing at all and your fancy deep model collapses into plain linear regression.', '[{"text":"Stacked into layers to build depth","id":"layer"},{"text":"Applied to the weighted sum from","id":"weights"}]'::jsonb, 'After a neuron adds up its weighted inputs, the activation function squashes or gates that number — ReLU zeroes out negatives, sigmoid squishes to 0–1. Without this nonlinearity, stacking layers gains you nothing: a pile of linear steps is still just one linear step.', 'It’s plumbing you’ll never tune, but it’s the reason a model can learn anything shaped like the real world.', 'A nonlinearity (ReLU, GELU, sigmoid) applied elementwise after the affine transform, giving the network capacity to approximate nonlinear functions.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('hiddenstate', 'Hidden state', '', '', ARRAY['hidden state']::text[], 'Core', 'The model’s running scratchpad — the numbers it carries in its head between input and answer.', 'Your train of thought mid-sentence: not the words on the page yet, just the shape of what you’re about to say.', 'When a chatbot “remembers” the start of your paragraph while finishing it, that memory lives in the hidden state, not the visible text.', '[{"text":"Lives in a high-dimensional","id":"latentspace"},{"text":"A kind of","id":"representation"}]'::jsonb, 'At each layer, every token gets a vector of numbers — its hidden state — that encodes meaning-so-far. These aren’t words; they’re high-dimensional representations the next layer reads and rewrites. The final one gets turned back into a prediction over the vocabulary.', 'It’s the internal “understanding” you can’t see and can’t directly edit — only shape through inputs.', 'The intermediate activation vector at a given layer and position, dimension d_model, passed forward through the stack.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('layer', 'Layer', '', '', ARRAY['layer']::text[], 'Core', 'One floor of the model — a repeatable block of math the input passes through on its way up.', 'An assembly-line station: each does a small transform and hands the part to the next; stack enough and a raw blank becomes a finished thing.', 'GPT-style models stack dozens of identical layers; “deeper” usually just means more of them bolted on top.', '[{"text":"Made of neurons using an","id":"activationfunction"},{"text":"Stacking many is","id":"deeplearning"}]'::jsonb, 'In a transformer, each layer is attention plus a feed-forward network, wrapped in residual connections and normalization. The input’s representation gets refined a little at every layer — early ones catch surface patterns, later ones catch abstract meaning.', 'More layers roughly means more capacity and more cost; depth is one of the dials behind “bigger model.”', 'A single transformer block: multi-head self-attention + FFN + residual + norm, repeated N times.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('deeplearning', 'Deep learning', '', '', ARRAY['deep learning','dl']::text[], 'Core', 'Machine learning with many stacked layers, so the model learns its own features instead of being handed them.', 'Teaching someone to cook by letting them ruin a thousand dishes, rather than writing out every rule for every ingredient.', 'Image recognition jumped from hand-crafted edge detectors to deep learning around 2012, and never looked back.', '[{"text":"A branch of","id":"machinelearning"},{"text":"Built from stacked","id":"layer"},{"text":"Runs on a","id":"neuralnetwork"}]'::jsonb, 'The “deep” is literal: many layers between input and output. Each layer builds on the last, so the network discovers useful representations on its own from raw data. It’s expensive and data-hungry, but it scales in a way older methods didn’t.', 'It’s the engine under nearly every modern AI product — the reason the last decade happened.', 'Neural networks with many hidden layers trained by backpropagation and gradient descent.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('machinelearning', 'Machine learning', '', '', ARRAY['machine learning','ml']::text[], 'Core', 'Programming by example — you show the computer data instead of writing the rules yourself.', 'Training a dog with treats rather than handing it an instruction manual.', 'A spam filter that learns from which emails you mark as junk is machine learning; a fixed “block anything with FREE MONEY” rule is not.', '[{"text":"A subfield is","id":"deeplearning"},{"text":"The umbrella above it is","id":"artificialintelligence"}]'::jsonb, 'Instead of a human coding logic step by step, an algorithm adjusts its own parameters to fit patterns in data. Give it examples, it finds the mapping. The catch: it’s only as good, and as biased, as the data you feed it.', 'It shines when rules are too messy to write by hand but examples are plentiful.', 'Algorithms that improve on a task by optimizing parameters against data, rather than via explicit programming.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('artificialintelligence', 'Artificial intelligence', '', '', ARRAY['artificial intelligence','ai']::text[], 'Core', 'The broad goal of getting machines to do things that used to need a human mind.', '“Vehicle” to “car” — AI is the whole category; today’s chatbots are one make and model inside it.', 'A chess engine, a spam filter, and a chatbot are all “AI,” which is why the word explains almost nothing on its own.', '[{"text":"Its dominant modern method is","id":"machinelearning"},{"text":"The generative flavor is","id":"generativeai"}]'::jsonb, 'AI is the umbrella term for machines performing cognitive-seeming tasks. It stretches from hand-coded rule systems to modern learned models. Most of what people mean by “AI” today is a narrow slice: large models trained on data, not anything with general understanding.', 'Useful as a banner, useless as a spec — always ask which technique someone actually means.', 'The field encompassing symbolic systems, classical ML, and deep learning aimed at intelligent behavior.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('generativeai', 'Generative AI', '', '', ARRAY['generative ai','genai']::text[], 'Core', 'AI that makes new stuff — text, images, code, audio — rather than just sorting or scoring what already exists.', 'The difference between a critic who rates paintings and an artist who paints new ones.', 'Asking a model to write a poem or generate a product mockup is generative AI; asking it to label a photo “cat” is not.', '[{"text":"Language versions are","id":"llm"},{"text":"Works by","id":"nexttokenprediction"}]'::jsonb, 'Generative models learn the shape of their training data well enough to sample fresh examples from it. For language, that’s predicting the next token over and over. The output is novel in wording but bounded by what the training distribution taught it.', 'It opened AI to creative and drafting work, which is why it went mainstream so fast.', 'Models that learn a data distribution and sample from it, e.g. autoregressive LLMs or diffusion image models.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('autoregressive', 'Autoregressive', '', '', ARRAY['autoregressive','auto-regressive']::text[], 'Core', 'Writing one token at a time, each new word chosen from all the words so far — including the ones it just wrote.', 'Predictive text that keeps going: it guesses the next word, commits, then guesses again from the fuller sentence.', 'When a model streams its answer word by word on screen, you’re literally watching autoregression happen.', '[{"text":"The mechanism behind","id":"nexttokenprediction"},{"text":"Emits one","id":"tokens"}]'::jsonb, 'Each step feeds the model everything generated up to now and asks for the next token. That token gets appended and the loop repeats. It’s why generation is sequential and can’t fully parallelize, and why an early wrong turn can snowball.', 'It’s why responses stream in and why latency scales with output length.', 'Factorizing p(sequence) as a product of next-token conditionals, decoding left to right.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('nexttokenprediction', 'Next-token prediction', '', '', ARRAY['next-token prediction','next token prediction']::text[], 'Core', 'The entire job of a language model: given some text, guess what comes next.', 'Finishing your friend’s sentence — do it well enough, billions of times, and it looks like understanding.', 'Type “The capital of France is” and the model predicts “Paris” as the most likely next token.', '[{"text":"Done repeatedly, it is","id":"autoregressive"},{"text":"Where it goes wrong is","id":"hallucination"}]'::jsonb, 'During training the model sees oceans of text and repeatedly guesses the next token, getting corrected each time. That single objective, at scale, is enough to produce grammar, facts, and reasoning-shaped behavior. It’s astonishingly simple, and its limits — it predicts likely, not true — come straight from the objective.', 'Remember the model optimizes for “plausible next word,” not “correct answer” — that gap is where hallucination lives.', 'The self-supervised pretraining objective: minimize cross-entropy of the true next token.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('probabilitydistribution', 'Probability distribution', '', '', ARRAY['probability distribution']::text[], 'Core', 'A spread of chances across all the options — how the model splits its confidence over every possible next token.', 'A weighted die: not every face equally likely, and the weights tell you where the model’s leaning.', 'After “The sky is”, the model might put 60% on “blue”, 10% on “clear”, and thin slices on thousands of others.', '[{"text":"Produced by","id":"softmax"},{"text":"Sharpened or flattened by","id":"temperature"},{"text":"Picked from via","id":"sampling"}]'::jsonb, 'At each step the model outputs a number for every token in its vocabulary, then softmax turns those into probabilities that sum to one. Sampling picks from this distribution. Temperature and top-p are just knobs that reshape it before the pick.', 'The model rarely “knows” one answer — it holds a spread, and your settings decide how boldly it commits.', 'The softmax output over the vocabulary; the categorical distribution sampled at each decode step.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('vector', 'Vector', '', '', ARRAY['vector']::text[], 'Core', 'A list of numbers that stands in for a thing, so a computer can do math on meaning.', 'GPS coordinates for an idea — a handful of numbers that pin it to a spot you can measure distances from.', 'The word “dog” might become [0.2, -1.1, 0.7, …], and “puppy” lands nearby in the same number-space.', '[{"text":"Meaningful ones are","id":"embeddings"},{"text":"Live in a","id":"latentspace"}]'::jsonb, 'Almost everything inside a model is a vector: tokens, hidden states, embeddings. Represent things as vectors and “similar” becomes “close”, “combine” becomes “add”. The dimensions rarely mean anything human-readable, but distances and directions carry real structure.', 'It’s the common currency that lets a model compare, search, and relate anything to anything.', 'An ordered array of floats in R^d; the basic unit of representation throughout the network.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('dimensionality', 'Dimensionality', '', '', ARRAY['dimensionality','dimensions']::text[], 'Core', 'How many numbers are in each vector — the size of the space the model thinks in.', 'Describing a person by 2 traits vs 500: more dimensions, more nuance, but harder to picture.', 'An embedding model might output 1,536-dimensional vectors; each of those slots captures some sliver of meaning.', '[{"text":"The length of a","id":"vector"},{"text":"Defines the","id":"latentspace"}]'::jsonb, 'Higher dimensionality lets a model encode more distinctions, but costs memory and compute and eventually hits diminishing returns. Weird things happen in high dimensions — distances flatten out — which is why similarity math has to be chosen carefully.', 'Bigger embedding dimensions can mean richer matching, but also more storage and slower search.', 'The size d of the vector space; trades representational capacity against compute and the curse of dimensionality.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('latentspace', 'Latent space', '', '', ARRAY['latent space']::text[], 'Core', 'The hidden map where the model arranges everything it knows, with similar things placed near each other.', 'A vast library where books shelve themselves by meaning, not by title — cookbooks drift together without anyone labeling the aisle.', 'In a good latent space, “king” minus “man” plus “woman” lands you near “queen”.', '[{"text":"Made of","id":"vector"},{"text":"Its width is","id":"dimensionality"},{"text":"Points in it are","id":"embeddings"}]'::jsonb, '“Latent” means hidden: it’s the internal coordinate system a model learns, where position encodes meaning. You never see it directly, but retrieval, clustering, and analogies all work because related concepts cluster there. The geometry is learned, not designed.', 'It’s why semantic search “just knows” two differently-worded things mean the same — they sit close in this space.', 'The learned embedding manifold; a continuous vector space where proximity reflects semantic or feature similarity.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('representation', 'Representation', '', '', ARRAY['representation']::text[], 'Core', 'How a model re-encodes something into its own internal language of numbers.', 'Sheet music for a song — not the sound itself, but a form the performer can actually work from.', 'A photo of a cat becomes a representation — a stack of numbers — before the model can classify or caption it.', '[{"text":"Stored as a","id":"vector"},{"text":"The learned kind is an","id":"embeddings"},{"text":"Learning good ones is","id":"deeplearning"}]'::jsonb, 'Deep learning’s whole trick is learning good representations: turning raw input into vectors where the useful structure is easy to read off. Better representations make downstream tasks easier. Much of what pretraining buys you is reusable representations.', 'The quality of a model’s internal representations sets the ceiling on everything it can do downstream.', 'A learned feature vector encoding input; the output of intermediate layers used by downstream heads.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('feature', 'Feature', '', '', ARRAY['feature']::text[], 'Core', 'A single measurable trait the model uses as a clue — one ingredient in its decision.', 'The tells a doctor reads: temperature, pulse, symptoms. Each is a feature; together they point to a diagnosis.', 'In old-school ML you’d hand-pick features like “word count” or “has a link”; deep learning learns its own instead.', '[{"text":"Learned automatically in","id":"deeplearning"},{"text":"Bundled into a","id":"representation"}]'::jsonb, 'A feature is one dimension of information about an input. Classical ML lived or died on humans engineering good features. Deep learning’s leap was learning features automatically from raw data, layer by layer, so the useful ones emerge without being named.', 'Where features come from — hand-built vs learned — is the line between old ML and modern AI.', 'An input variable or a learned activation dimension; the axes along which a model discriminates.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('weightsandbiases', 'Weights and biases', '', '', ARRAY['weights and biases']::text[], 'Core', 'The two kinds of knobs a network learns: weights scale each input, biases nudge the result.', 'A recipe where weights are how much of each ingredient and the bias is the pinch of salt added no matter what.', 'Training a model means slowly turning billions of these weights and biases until the outputs stop being wrong.', '[{"text":"Collectively the","id":"parameters"},{"text":"The weight half is","id":"weights"},{"text":"The nudge is a","id":"biasterm"}]'::jsonb, 'Each neuron multiplies its inputs by weights, sums them, and adds a bias, then applies an activation. Weights decide what matters; the bias shifts the threshold for firing. Every “parameter” you hear about is one of these numbers, and learning is just adjusting them.', '“Number of parameters” is essentially a count of these knobs — a rough proxy for a model’s raw capacity.', 'The learnable affine parameters W and b in y = Wx + b, updated by gradient descent.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('biasterm', 'Bias term', '', '', ARRAY['bias term','bias']::text[], 'Core', 'A constant a neuron adds no matter what, so it isn’t forced to pass through zero.', 'The base fare on a taxi meter — you pay it before the distance charge even starts.', 'Without a bias, a neuron given all-zero input must output zero; the bias lets it say something else.', '[{"text":"The partner of","id":"weights"},{"text":"Together they are","id":"weightsandbiases"}]'::jsonb, 'In y = Wx + b, the bias is b: a learnable offset that shifts the activation up or down independent of the input. Small thing, but it gives each neuron freedom to set its own baseline. Note: “bias” here is unrelated to fairness or social bias — same word, different sense.', 'Pure mechanism; matters to you mainly as a reminder that model “bias” has two totally different meanings.', 'The additive constant b in an affine layer, one learnable scalar per output unit.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('forwardpass', 'Forward pass', '', '', ARRAY['forward pass']::text[], 'Core', 'Running input through the model start to finish to get an output — no learning, just computing.', 'Feeding a coin into a vending machine and watching the can drop: input goes in, result comes out, nothing about the machine changes.', 'Every time you send a prompt and get an answer, that’s one forward pass through billions of parameters.', '[{"text":"At output it produces","id":"logits"},{"text":"Running it is","id":"inference"}]'::jsonb, 'Data flows from the input through each layer’s math to the output. During training this is paired with a backward pass that computes gradients; at inference it’s all you run. It’s what you pay for per request — compute proportional to model size and sequence length.', 'Inference cost is basically the price of one forward pass — bigger model or longer input, bigger bill.', 'Evaluation of the network’s function on an input, producing activations and logits, without gradient updates.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('matrixmultiplication', 'Matrix multiplication', '', '', ARRAY['matrix multiplication','matmul']::text[], 'Core', 'The bulk math behind a model — grids of numbers multiplied together, billions of times a second.', 'A spreadsheet where every cell is a weighted sum of a row and a column, computed all at once.', 'The reason GPUs run AI is that they’re built to do enormous matrix multiplications in parallel.', '[{"text":"Its building block is the","id":"dotproduct"},{"text":"Applies the","id":"weights"}]'::jsonb, 'A layer’s core operation is multiplying an input matrix by a weight matrix. Almost all of a model’s compute is this one operation, which is why hardware is designed around it. Understand matmul and you understand where the FLOPs go.', 'It’s the workload GPUs are optimized for — the physical reason AI compute costs what it does.', 'The dominant kernel: dense GEMM operations that consume most training and inference FLOPs.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('dotproduct', 'Dot product', '', '', ARRAY['dot product']::text[], 'Core', 'Multiply two lists of numbers pairwise and add it all up — one number that says how aligned they are.', 'Scoring how well two playlists match: multiply overlapping tastes, sum the score, higher means more alike.', 'Attention scores “how much should token A care about token B” with a dot product of their vectors.', '[{"text":"Composed into","id":"matrixmultiplication"},{"text":"Normalized becomes","id":"cosinesimilarity"}]'::jsonb, 'The dot product of two vectors sums the products of matching components. It’s the atom of matrix multiplication and the cheapest measure of similarity — big and positive when vectors point the same way, near zero when unrelated. Normalize it and you get cosine similarity.', 'It’s the tiny operation underneath “how similar are these two things” across search and attention.', '⟨a,b⟩ = Σ aᵢbᵢ; the elementary op composing matmul and the unnormalized similarity in attention.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('cosinesimilarity', 'Cosine similarity', '', '', ARRAY['cosine similarity']::text[], 'Core', 'How similar two vectors are by direction, ignoring how long they are — 1 is identical, 0 is unrelated.', 'Two people pointing: it’s whether they point the same way that matters, not how far their arms reach.', 'Semantic search ranks results by cosine similarity between your query’s embedding and each document’s.', '[{"text":"Built from the","id":"dotproduct"},{"text":"Used to compare","id":"embeddings"},{"text":"Powers search over a","id":"vectordatabase"}]'::jsonb, 'It’s the dot product divided by both vectors’ lengths, which strips out magnitude and leaves only angle. That makes it robust when vectors have different scales. It’s the default similarity metric for embeddings because meaning tends to live in direction, not length.', 'It’s the math that decides which stored items count as “closest” to a query in most vector search.', 'cosθ = ⟨a,b⟩ / (‖a‖‖b‖); angle-based similarity invariant to vector magnitude.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('normalization', 'Normalization', '', '', ARRAY['normalization','normalize']::text[], 'Core', 'Rescaling numbers to a sane, consistent range so training doesn’t wobble or blow up.', 'Adjusting every photo to the same brightness before comparing them, so lighting doesn’t fool you.', 'Deep networks add normalization between layers to keep the signal from exploding or vanishing as it goes deep.', '[{"text":"The transformer favorite is","id":"layernormalization"},{"text":"The older vision trick is","id":"batchnormalization"}]'::jsonb, 'Activations can drift to wildly different scales, which makes gradients unstable. Normalization re-centers and re-scales them, keeping the network in a well-behaved zone so it trains faster and deeper. The main variants differ in what they average over.', 'Invisible plumbing, but it’s a big reason very deep models train at all.', 'Standardizing activations (subtract mean, divide by std) to stabilize gradients; see LayerNorm, BatchNorm.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('layernormalization', 'Layer normalization', '', '', ARRAY['layer normalization','layernorm']::text[], 'Core', 'Normalization done across each token’s own features — the version transformers actually use.', 'Grading each student against their own average across subjects, not against the whole class.', 'Every transformer block sandwiches its attention and feed-forward steps with layer norm to stay stable.', '[{"text":"A flavor of","id":"normalization"},{"text":"Wraps each","id":"layer"}]'::jsonb, 'LayerNorm normalizes across the feature dimension for each token independently, so it doesn’t depend on other examples in the batch. That independence is why it plays nicely with variable-length sequences and small batches, unlike batch norm. It’s a quiet workhorse of the transformer.', 'One of those default design choices you inherit for free in any modern model.', 'Normalizes over the feature axis per position; batch-size-independent, standard in transformers.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('batchnormalization', 'Batch normalization', '', '', ARRAY['batch normalization','batchnorm']::text[], 'Fading', 'Normalization computed across a batch of examples — huge for vision, awkward for language.', 'Curving a test using the whole class’s scores that day: great when the class is big and stable, shaky when it’s tiny.', 'ResNets and image models lean on batch norm; transformers mostly skipped it for layer norm.', '[{"text":"A flavor of","id":"normalization"},{"text":"Supplanted in NLP by","id":"layernormalization"}]'::jsonb, 'BatchNorm normalizes each feature using statistics across the current batch. It accelerated deep vision training dramatically, but its batch-dependence causes trouble with small batches, variable sequence lengths, and inference-time mismatch. Language models largely moved on.', 'Mostly a vision-era tool; if you’re in language land you’ll rarely touch it.', 'Normalizes over the batch dimension per feature; batch-dependent, dominant in CNNs, rare in transformers.', 'Foundations', 30, ARRAY['seed','foundations']::text[]),
  ('dropout', 'Dropout', '', '', ARRAY['dropout']::text[], 'Core', 'Randomly switching off part of the network during training so it can’t over-rely on any one path.', 'Making a team practice with random players benched, so no single star becomes a crutch.', 'A model prone to memorizing its training data might use dropout to force more robust, spread-out learning.', '[{"text":"Fights","id":"overfitting"},{"text":"Improves","id":"generalization"}]'::jsonb, 'During training, dropout zeroes a random fraction of activations each step, so neurons must learn redundant, general features instead of brittle co-dependencies. It’s a cheap, effective regularizer against overfitting. At inference it’s turned off and the full network runs.', 'A standard anti-overfitting knob — it trades a little training speed for better generalization.', 'Stochastically masks activations with probability p at train time; a regularizer disabled at inference.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('overfitting', 'Overfitting', '', '', ARRAY['overfitting','overfit']::text[], 'Core', 'When a model memorizes its training data instead of learning the pattern, and flops on anything new.', 'A student who memorizes the practice exam word for word, then panics when the real questions are reworded.', 'A model that scores 99% on training data but 60% on fresh data is overfit — it learned the answers, not the lesson.', '[{"text":"The opposite is","id":"underfitting"},{"text":"The goal it violates is","id":"generalization"},{"text":"Countered by","id":"dropout"}]'::jsonb, 'Overfitting happens when a model has enough capacity to fit noise and quirks specific to the training set. It looks great in training and fails to generalize. Remedies include more data, regularization like dropout, and stopping training before it starts memorizing.', 'It’s why a model that “aced testing” can still disappoint in production — check performance on held-out data.', 'Low training loss but a high generalization gap; the model fits noise rather than signal.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('underfitting', 'Underfitting', '', '', ARRAY['underfitting','underfit']::text[], 'Core', 'When a model is too simple or undertrained to even capture the pattern — bad everywhere, including training.', 'Trying to trace a curvy coastline with a single straight ruler: you miss no matter how you place it.', 'A tiny model on a hard task might sit at 55% on both training and test data — it never had the capacity to learn it.', '[{"text":"The opposite is","id":"overfitting"},{"text":"Both are failures of","id":"generalization"}]'::jsonb, 'Underfitting is high error even on the training set: the model lacks the capacity, the features, or the training time to fit the data. The fix is the opposite of overfitting’s — more capacity, better features, longer training. The art is landing between the two.', 'If a model is mediocre even on data it’s seen, the problem is capacity or training, not just tuning.', 'High bias: the model class is too constrained to fit the underlying function.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('generalization', 'Generalization', '', '', ARRAY['generalization','generalize']::text[], 'Core', 'The whole point — doing well on data the model has never seen, not just the examples it trained on.', 'Learning to ride any bike, not just the exact one you practiced on.', 'A well-generalized spam filter catches brand-new scam wording it never saw in training.', '[{"text":"Broken by","id":"overfitting"},{"text":"Also broken by","id":"underfitting"}]'::jsonb, 'Generalization is the gap between training performance and real-world performance. Everything in ML — regularization, validation sets, more data — is ultimately in service of closing it. Overfitting and underfitting are the two ways it breaks.', 'It’s the only performance number that matters — measure on data the model hasn’t seen.', 'Expected performance on the true data distribution, estimated via held-out/test error.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('inference', 'Inference', '', '', ARRAY['inference']::text[], 'Core', 'Using a trained model to actually answer — the running phase, as opposed to the learning phase.', 'The difference between studying for the exam and sitting it: inference is test day, no more learning.', 'Every prompt you send to a chatbot is inference; the months of training happened long before you showed up.', '[{"text":"One is a","id":"forwardpass"},{"text":"The opposite phase is","id":"training"}]'::jsonb, 'Inference is a forward pass on new input with frozen weights — no gradients, no updates. It’s what you pay for per request and what latency and throughput optimizations target. Training is a one-time (huge) cost; inference is the ongoing one.', 'This is your recurring cost line — it scales with usage, unlike training’s one-time hit.', 'Forward-pass evaluation with fixed parameters; the serving/decoding phase, optimized for latency and throughput.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('training', 'Training', '', '', ARRAY['training','train']::text[], 'Core', 'Teaching the model by showing it data and nudging its parameters until the answers get better.', 'Tuning a piano by ear: play, hear what’s off, adjust the string, repeat thousands of times.', 'Training a frontier model can take months on thousands of GPUs before it ever answers a single user.', '[{"text":"The opposite phase is","id":"inference"},{"text":"Adjusts the","id":"weights"},{"text":"Produces a","id":"basemodel"}]'::jsonb, 'Training runs data through the model, measures error with a loss function, and uses backpropagation and gradient descent to adjust weights. Repeat over enormous data and it slowly learns. It’s the expensive, upfront phase; the result is a frozen set of parameters you then run at inference.', 'It’s the big upfront capital cost; most products consume a model someone else already trained.', 'Iterative parameter optimization via forward pass, loss, backprop, and gradient updates over a dataset.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('modelsize', 'Model size', '', '', ARRAY['model size']::text[], 'Core', 'Roughly how big a model is, usually counted in parameters — the headline number everyone quotes.', 'Engine displacement on a car: bigger often means more power, but it’s not the whole story.', 'A “70B” model has 70 billion parameters; a “7B” has ten times fewer, and runs far cheaper.', '[{"text":"Counted as","id":"parameters"},{"text":"Trades off in a","id":"frontiermodel"}]'::jsonb, 'Size is usually parameter count, a proxy for capacity. Bigger models tend to be more capable but cost more to train and run, and need more data to earn their size. Recent trends show a well-trained small model can beat a bloated large one — size is a dial, not a destiny.', 'Bigger isn’t automatically better; weigh capability against latency and cost for your task.', 'Parameter count (and by extension memory/FLOPs); one axis of the scaling-law trade-off.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('modelfamily', 'Model family', '', '', ARRAY['model family']::text[], 'Core', 'A set of models from the same lineage, usually offered in several sizes.', 'A car model offered as a hatchback, sedan, and SUV — same DNA, different sizes for different needs.', 'Picking between the small, medium, and large versions of one release means choosing within a model family.', '[{"text":"Members differ in","id":"modelsize"},{"text":"The untuned root is a","id":"basemodel"}]'::jsonb, 'A family shares architecture and training recipe, released in multiple sizes and sometimes tuned variants. This lets you trade capability for cost without switching ecosystems. Prompts and behavior tend to transfer within a family more cleanly than across families.', 'Standardizing on one family lets you swap sizes for cost/quality without rewriting everything.', 'Models sharing architecture and training lineage, differentiated mainly by scale and fine-tune.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('checkpoint', 'Checkpoint', '', '', ARRAY['checkpoint']::text[], 'Core', 'A saved snapshot of a model’s parameters at a moment in training, so you can stop, resume, or ship it.', 'A save point in a video game — freeze progress now, come back to exactly here later.', 'If a training run crashes at hour 300, you reload the last checkpoint instead of starting over.', '[{"text":"Saves the","id":"weights"},{"text":"Captured during","id":"training"}]'::jsonb, 'A checkpoint is the full set of weights written to disk mid- or post-training. It lets you resume interrupted runs, compare versions, roll back a bad update, or deploy a specific state. “The model you use” is really one chosen checkpoint.', 'Every deployed model is a specific checkpoint — pin the version so behavior doesn’t shift under you.', 'Serialized parameter (and optimizer) state at a training step, used for resumption and deployment.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('modelcard', 'Model card', '', '', ARRAY['model card']::text[], 'Rising', 'A short spec sheet for a model — what it’s for, what it was trained on, and where it falls down.', 'The nutrition label on food: not the meal, but what you should know before consuming it.', 'Before adopting a model, a team reads its model card for the license, known limitations, and eval scores.', '[{"text":"Describes a","id":"basemodel"},{"text":"May cite","id":"evals"}]'::jsonb, 'A model card documents intended use, training data at a high level, evaluation results, and known risks or biases. It’s a transparency and governance artifact more than a technical one. Quality varies wildly, but it’s the first thing to check before you build on something.', 'Your first due-diligence read — license, intended use, and stated limits can make or break adoption.', 'Structured documentation of a model’s scope, data, metrics, and limitations, per the model-cards convention.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('openweights', 'Open weights', '', '', ARRAY['open weights','open-weights']::text[], 'Rising', 'A model whose trained parameters you can download and run yourself, no API required.', 'Getting the actual recipe and cooking at home, versus only being able to order the dish.', 'With an open-weights model you can self-host on your own servers and fine-tune it privately.', '[{"text":"The opposite is a","id":"closedmodel"},{"text":"Ships the","id":"weights"}]'::jsonb, 'Open weights means the parameter files are released, so you can run, inspect, and fine-tune locally. It’s not the same as fully open source — training data and code may stay private, and licenses can restrict use. The trade is control and privacy for the burden of hosting it yourself.', 'Open weights buy you self-hosting, privacy, and customization — at the cost of running the infrastructure.', 'Downloadable parameter files for local inference/fine-tuning; distinct from open training data or code.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('closedmodel', 'Closed model', '', '', ARRAY['closed model','proprietary model']::text[], 'Core', 'A model you can only reach through someone’s API — the weights stay locked behind the vendor’s door.', 'A restaurant kitchen you order from but never enter; you get the dish, never the recipe.', 'Using a top proprietary model means sending prompts to its API and getting answers back — you never hold the weights.', '[{"text":"The opposite is","id":"openweights"},{"text":"Often a","id":"frontiermodel"}]'::jsonb, 'Closed models keep parameters private and are served via API. You trade control and data locality for convenience, managed scaling, and often frontier quality. The risks are lock-in, price changes, and sending your data to a third party.', 'Fastest path to frontier quality, but watch for lock-in, data exposure, and pricing you don’t control.', 'API-gated model with undisclosed weights; you consume inference without hosting or inspecting it.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('densemodel', 'Dense model', '', '', ARRAY['dense model']::text[], 'Core', 'A model where every parameter fires on every token — the standard, straightforward design.', 'A restaurant where the whole kitchen cooks every order, versus one that pages only the relevant chef.', 'A classic dense 7B model uses all 7 billion parameters for each token; a sparse model of the same total wouldn’t.', '[{"text":"The opposite is a","id":"sparsemodel"},{"text":"Cost scales with","id":"modelsize"}]'::jsonb, 'In a dense model the full weight set participates in every forward pass. It’s simple and predictable but means compute scales directly with size. The alternative, sparse mixture-of-experts, activates only a slice per token to get more capacity for less compute.', 'Predictable cost and behavior; you pay for the whole model on every token.', 'All parameters active per token; compute ∝ parameter count, contrasted with sparse MoE routing.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('sparsemodel', 'Sparse model', '', '', ARRAY['sparse model']::text[], 'Rising', 'A model that switches on only the parameters it needs per token, so it can be huge but cheap to run.', 'A big hospital where each patient sees just the right specialists, not every doctor on staff.', 'A mixture-of-experts model might hold eight times the parameters of a dense one but only light up a fraction per token.', '[{"text":"The opposite is a","id":"densemodel"},{"text":"Grows total","id":"parameters"}]'::jsonb, 'Sparse models — chiefly mixture-of-experts — route each token to a few “expert” subnetworks instead of the whole thing. That decouples total capacity from per-token compute: more knowledge, similar cost. The catch is added complexity in routing, load balancing, and serving.', 'The trick behind models that are “enormous” yet affordable to run — capacity without proportional cost.', 'Conditional computation (e.g. MoE) activating a subset of parameters per token via a router.', 'Foundations', 60, ARRAY['seed','foundations']::text[]),
  ('contextlength', 'Context length', '', '', ARRAY['context length']::text[], 'Core', 'The maximum amount of text a model can consider at once, prompt plus answer combined.', 'The size of a desk: only so many papers fit in view before older ones fall off the edge.', 'A 128K context length can hold a small book; exceed it and the earliest text gets dropped.', '[{"text":"Measured in","id":"tokens"},{"text":"The window itself is the","id":"contextwindow"},{"text":"Compared with","id":"sequencelength"}]'::jsonb, 'Context length caps the tokens the model attends to in a single call. Everything — instructions, retrieved docs, history, output — competes for that budget. Longer contexts unlock bigger tasks but cost more and can suffer “lost in the middle” attention issues.', 'It’s a hard budget you’re always managing — long docs, history, and output all share it.', 'Max sequence length the model can attend over; bounded by positional scheme and attention cost.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('sequencelength', 'Sequence length', '', '', ARRAY['sequence length','seq len']::text[], 'Core', 'How many tokens are actually in a given input or output right now.', 'The number of cars in the train you’re running today, versus how long the platform can hold.', 'A 500-token prompt has a sequence length of 500, well under a 128K context limit.', '[{"text":"Capped by","id":"contextlength"},{"text":"Counted in","id":"tokens"}]'::jsonb, 'Sequence length is the count of tokens being processed in a specific pass, while context length is the ceiling. Attention cost grows roughly with the square of sequence length, which is why long inputs get expensive fast. Keeping sequences tight is a real performance lever.', 'Shorter sequences mean lower latency and cost — trimming inputs is a cheap optimization.', 'The token count n of a given batch element; attention is O(n²) in it.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('prompt', 'Prompt', '', '', ARRAY['prompt']::text[], 'Core', 'The input you give a model — the text that sets up what you want it to do.', 'The brief you hand a freelancer: how good the work is depends a lot on how clear you were.', '“Summarize this email in two sentences” plus the email is the prompt; the summary is the completion.', '[{"text":"The model replies with a","id":"completion"},{"text":"Crafting it well is","id":"promptengineering"}]'::jsonb, 'The prompt is everything you feed in: instructions, context, examples, the actual question. The model conditions its entire response on it. Because behavior is so sensitive to wording, prompting is a real skill — though robust models need less coaxing than they used to.', 'Often the cheapest lever you have — rewording the prompt beats fine-tuning for many problems.', 'The input token sequence conditioning generation; includes system, user, and any in-context examples.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('completion', 'Completion', '', '', ARRAY['completion']::text[], 'Core', 'The model’s output — the text it generates to continue or answer your prompt.', 'The reply to your letter: you wrote the prompt, this is what comes back.', 'Send “Write a haiku about rain” and the three-line poem you get is the completion.', '[{"text":"Responds to a","id":"prompt"},{"text":"Built one token at a time via","id":"autoregressive"}]'::jsonb, 'Completion is what the model produces token by token in response to the prompt. The name comes from the original framing — the model “completes” the text you started. Its length counts against your context budget and drives most of your latency.', 'You pay for completion tokens too, and they usually dominate latency — long answers cost more twice over.', 'The generated continuation; the decoded token sequence following the prompt.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('systemmessage', 'System message', '', '', ARRAY['system message','system prompt']::text[], 'Core', 'A special up-front instruction that sets the model’s role and rules for the whole conversation.', 'The job description you give a new hire on day one — it colors everything they do afterward.', '“You are a terse assistant that only answers in bullet points” as a system message shapes every reply that follows.', '[{"text":"Sits alongside the","id":"usermessage"},{"text":"Can be undermined by","id":"promptinjection"}]'::jsonb, 'The system message sits above the back-and-forth and defines persona, constraints, and priorities. Models are trained to weight it heavily, so it’s your main steering wheel for tone and behavior. It’s not bulletproof, though — clever user input can sometimes override it.', 'Your primary control surface for consistent behavior — but don’t treat it as a hard security boundary.', 'A high-priority role message prepended to the conversation, weighted above user turns in training.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('assistantmessage', 'Assistant message', '', '', ARRAY['assistant message']::text[], 'Core', 'A turn in the conversation spoken by the model itself.', 'The reply bubbles on one side of a text thread — the half of the chat that’s the model talking.', 'In a chat transcript, each thing the AI said is tagged as an assistant message.', '[{"text":"Alternates with the","id":"usermessage"},{"text":"The model output is a","id":"completion"}]'::jsonb, 'Chat models see conversations as tagged turns: system, user, and assistant. Assistant messages are the model’s own past replies, fed back in so it stays consistent across a multi-turn chat. You can also seed one to steer or continue a response.', 'Past assistant turns are part of the input — they shape and constrain what comes next.', 'A conversation turn with the assistant role; prior ones are re-fed to maintain multi-turn coherence.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('usermessage', 'User message', '', '', ARRAY['user message']::text[], 'Core', 'A turn in the conversation spoken by the person — what you actually type in.', 'Your side of the text thread: the questions and asks the other party responds to.', '“Can you make that shorter?” typed into a chatbot is a user message.', '[{"text":"Answered by an","id":"assistantmessage"},{"text":"Governed by the","id":"systemmessage"},{"text":"Entry point for","id":"promptinjection"}]'::jsonb, 'User messages carry the human’s requests within the tagged turn structure. The model reads the whole running sequence of system, user, and assistant turns to decide its next reply. Anything untrusted a user pastes in also lands here, which is why injection risk lives at this boundary.', 'This is where untrusted input enters — treat its contents as potentially adversarial.', 'A conversation turn with the user role; the primary untrusted input surface.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('turn', 'Turn', '', '', ARRAY['turn']::text[], 'Core', 'One message in a back-and-forth — one side saying one thing before the other responds.', 'A single volley in a tennis rally: one hit, then it’s the other player’s shot.', 'A five-turn conversation is roughly five exchanged messages between you and the model.', '[{"text":"Assembled into a","id":"conversation"},{"text":"Each has a role like","id":"usermessage"}]'::jsonb, 'Chat is modeled as a sequence of turns, each tagged with a role. The whole history of turns is what the model reads each time, so conversations grow token by token and eventually strain the context budget. Managing turns — trimming or summarizing old ones — is part of building chat apps.', 'Long chats silently eat context; at some point old turns must be trimmed or summarized.', 'A single role-tagged message unit; the granularity of conversation state.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('conversation', 'Conversation', '', '', ARRAY['conversation']::text[], 'Core', 'The full running thread of turns the model reads to keep a chat coherent.', 'The whole email chain, not just the latest reply — context you’d lose if you only read the bottom message.', 'When a chatbot recalls something from ten messages ago, it’s because the whole conversation is re-fed each turn.', '[{"text":"Made of","id":"turn"},{"text":"Bounded by","id":"contextlength"}]'::jsonb, 'A conversation is the ordered stack of system, user, and assistant turns. Models are largely stateless, so the app resends the accumulated history every call to simulate memory. That history grows until it bumps the context limit, forcing truncation or summarization.', 'The model’s “memory” is really just resent history — real long-term memory needs extra machinery.', 'The concatenated sequence of turns re-sent per request; statelessness simulated by replaying history.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('stochastic', 'Stochastic', '', '', ARRAY['stochastic']::text[], 'Core', 'Involving randomness — the reason the same prompt can give you different answers.', 'Rolling dice rather than reading a ruler: the outcome has a random element baked in.', 'Ask the same creative question twice and get two different poems — that’s stochastic sampling at work.', '[{"text":"The opposite is","id":"determinism"},{"text":"Comes from","id":"sampling"},{"text":"Tuned by","id":"temperature"}]'::jsonb, 'Generation is stochastic because the model samples from a probability distribution rather than always taking the top choice. Temperature and top-p control how random. It’s a feature for creativity and a headache for reproducibility — set temperature to zero (or fix a seed) to tame it.', 'It’s why outputs vary run to run — lower the temperature when you need consistency.', 'Sampling-based decoding introduces randomness; contrast with deterministic (greedy) decoding.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('determinism', 'Determinism', '', '', ARRAY['determinism','deterministic']::text[], 'Core', 'Same input, same output, every time — no surprises, no randomness.', 'A calculator: 2+2 is always 4, no mood, no dice.', 'Set temperature to zero and a model becomes (mostly) deterministic — repeat the prompt, repeat the answer.', '[{"text":"The opposite is","id":"stochastic"},{"text":"Achieved via","id":"greedydecoding"},{"text":"Pinned with a","id":"seed"}]'::jsonb, 'Deterministic decoding always picks the highest-probability token (greedy), removing run-to-run variation. It’s what you want for tests, caching, and reproducibility. True determinism can still be nudged by hardware and floating-point quirks, but temperature zero gets you most of the way.', 'Reach for it when you need repeatable, testable outputs rather than creative variety.', 'Greedy/argmax decoding yielding reproducible outputs; disturbed only by numerical nondeterminism.', 'Foundations', 80, ARRAY['seed','foundations']::text[]),
  ('seed', 'Seed', '', '', ARRAY['seed']::text[], 'Core', 'A number that fixes the randomness, so a “random” run can be repeated exactly.', 'Shuffling a deck the exact same way twice by starting from the same setup — random-looking, but repeatable.', 'Set the same seed and temperature, and a model can reproduce the identical “random” answer on demand.', '[{"text":"Tames","id":"stochastic"},{"text":"Supports","id":"determinism"}]'::jsonb, 'Random number generators are actually deterministic given a starting seed. Fixing the seed makes stochastic sampling reproducible, which is invaluable for debugging and fair comparisons. It only helps if the rest of the pipeline is pinned too — change the model or hardware and the guarantee weakens.', 'The knob that makes “random” outputs reproducible for testing and A/B comparisons.', 'The RNG seed initializing pseudo-random sampling; fixes decode randomness for reproducibility.', 'Foundations', 80, ARRAY['seed','foundations']::text[])
